// left[node] == -1 means leaf node
func eval(node int, f []float64) float64 {
	for {
		if left[node] < 0 {
			return value[node]
		}
		v := f[feature[node]]
		switch {
		case math.IsNaN(v):
			node = missing[node]
		case float32(v) < threshold[node]:
			node = left[node]
		default:
			node = right[node]
		}
	}
}

// Predict returns the regression score for feature vector f.
func Predict(f []float64) float64 {
	s := baseScore
	for _, root := range roots {
		s += eval(root, f)
	}
	return s
}
